public class SynchronizationExample {
    public static void main(String[] args) throws InterruptedException {
        // Without synchronization (race condition)
        System.out.println("=== Without Synchronization ===");
        Counter badCounter = new Counter();

        Thread t1 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) {
                badCounter.increment();  // Not synchronized!
            }
        });
        Thread t2 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) {
                badCounter.increment();  // Not synchronized!
            }
        });

        t1.start();
        t2.start();
        t1.join();
        t2.join();

        System.out.println("Expected: 2000, Got: " + badCounter.getValue());

        // With synchronization
        System.out.println("=== With Synchronization ===");
        SynchronizedCounter goodCounter = new SynchronizedCounter();

        Thread t3 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) {
                goodCounter.increment();  // Synchronized!
            }
        });
        Thread t4 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) {
                goodCounter.increment();  // Synchronized!
            }
        });

        t3.start();
        t4.start();
        t3.join();
        t4.join();

        System.out.println("Expected: 2000, Got: " + goodCounter.getValue());

        // Synchronized block (more granular)
        System.out.println("=== Synchronized Block ===");
        CounterWithBlock counterBlock = new CounterWithBlock();

        Thread t5 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) {
                counterBlock.increment();
            }
        });
        Thread t6 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) {
                counterBlock.increment();
            }
        });

        t5.start();
        t6.start();
        t5.join();
        t6.join();

        System.out.println("Expected: 2000, Got: " + counterBlock.getValue());

        // Synchronized static method
        System.out.println("=== Static Synchronization ===");
        Thread t7 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) {
                StaticCounter.increment();
            }
        });
        Thread t8 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) {
                StaticCounter.increment();
            }
        });

        t7.start();
        t8.start();
        t7.join();
        t8.join();

        System.out.println("Static counter: " + StaticCounter.getValue());
    }
}

// Unsynchronized counter
class Counter {
    private int value = 0;

    void increment() {
        value++;  // Not thread-safe!
    }

    int getValue() {
        return value;
    }
}

// Synchronized method
class SynchronizedCounter {
    private int value = 0;

    // Only one thread can access this at a time
    synchronized void increment() {
        value++;  // Thread-safe!
    }

    synchronized int getValue() {
        return value;
    }
}

// Synchronized block
class CounterWithBlock {
    private int value = 0;
    private final Object lock = new Object();

    void increment() {
        // Synchronize only the critical section
        synchronized (lock) {
            value++;
        }
    }

    int getValue() {
        synchronized (lock) {
            return value;
        }
    }
}

// Static synchronization
class StaticCounter {
    private static int value = 0;

    static synchronized void increment() {
        value++;
    }

    static int getValue() {
        return value;
    }
}

phase2.brokenCode:
public class Test {
    private static int counter = 0;

    public static void main(String[] args) throws Exception {
        Thread t1 = new Thread(() -> {
            for (int i = 0; i < 100000; i++) {
                // Forgetting to synchronize
                counter++;
            }
        });
        Thread t2 = new Thread(() -> {
            for (int i = 0; i < 100000; i++) {
                counter++;
            }
        });

        t1.start();
        t2.start();
        t1.join();
        t2.join();

        System.out.println("Counter: " + counter);  // Not 200000!
    }
}

phase2.explanation:
counter++ is NOT thread-safe! Even though it's a single line, it's three operations:
1. Read counter value
2. Increment value
3. Write counter value

Two threads can interleave these operations, causing lost updates.

FIX: Synchronize the critical section:

synchronized (Test.class) {
    counter++;
}

Or use AtomicInteger:
AtomicInteger counter = new AtomicInteger(0);
counter.incrementAndGet();  // Thread-safe, no synchronization needed!

Always identify and protect shared mutable state!

phase3.solution:
class BankAccount {
    private double balance;

    BankAccount(double initial) {
        this.balance = initial;
    }

    synchronized void deposit(double amount) {
        balance += amount;
    }

    synchronized void withdraw(double amount) {
        if (balance >= amount) {
            balance -= amount;
        } else {
            System.out.println("Insufficient balance!");
        }
    }

    synchronized double getBalance() {
        return balance;
    }
}

public class SynchronizationPractice {
    public static void main(String[] args) throws InterruptedException {
        BankAccount account = new BankAccount(1000);

        Thread[] deposits = new Thread[5];
        for (int i = 0; i < 5; i++) {
            deposits[i] = new Thread(() -> account.deposit(100));
            deposits[i].start();
        }

        Thread[] withdrawals = new Thread[3];
        for (int i = 0; i < 3; i++) {
            withdrawals[i] = new Thread(() -> account.withdraw(50));
            withdrawals[i].start();
        }

        // Wait for all threads to finish
        for (Thread t : deposits) t.join();
        for (Thread t : withdrawals) t.join();

        System.out.println("Final balance: $" + account.getBalance());
        System.out.println("Expected: $1350");
    }
}
